import json
import re
from collections import defaultdict

# Access file paths from storage
books_file_path = locals()['var_functions.query_db:28']
reviews_file_path = locals()['var_functions.query_db:26']

# Load data
with open(books_file_path, 'r') as f:
    books_data = json.load(f)

with open(reviews_file_path, 'r') as f:
    reviews_data = json.load(f)

# Extract publication years from book details
year_pattern = r'(\d{4})'
book_years = {}

for book in books_data:
    details = book.get('details', '')
    matches = re.findall(year_pattern, details)

    if matches:
        for match in matches:
            year = int(match)
            if 1800 <= year <= 2024:
                book_years[book['book_id']] = year
                break

# Group ratings by book decade
decade_ratings = defaultdict(list)
book_decades = {}

for book_id, year in book_years.items():
    decade = (year // 10) * 10
    book_decades[book_id] = decade

# Process reviews and match with book decades
for review in reviews_data:
    purchase_id = review.get('purchase_id')
    rating = float(review.get('rating', 0))

    # Convert purchase_id to book_id format
    # purchaseid_xxx -> bookid_xxx
    book_id = purchase_id.replace('purchaseid_', 'bookid_')

    if book_id in book_decades:
        decade = book_decades[book_id]
        decade_ratings[decade].append({
            'book_id': book_id,
            'rating': rating
        })

# Calculate statistics per decade
decade_stats = {}
for decade, ratings in decade_ratings.items():
    # Group ratings by book
    book_ratings = {}
    for item in ratings:
        book_id = item['book_id']
        if book_id not in book_ratings:
            book_ratings[book_id] = []
        book_ratings[book_id].append(item['rating'])

    # Calculate average rating per book
    book_avg_ratings = []
    for book_id, ratings_list in book_ratings.items():
        avg_rating = sum(ratings_list) / len(ratings_list)
        book_avg_ratings.append(avg_rating)

    # Statistics for decade
    if len(book_avg_ratings) >= 10:  # At least 10 distinct books required
        decade_stats[decade] = {
            'avg_rating': sum(book_avg_ratings) / len(book_avg_ratings),
            'num_books': len(book_avg_ratings),
            'total_reviews': len(ratings)
        }

# Find decade with highest average rating
if decade_stats:
    best_decade = max(decade_stats.items(), key=lambda x: x[1]['avg_rating'])

    result = {
        'best_decade': f"{best_decade[0]}s",
        'avg_rating': best_decade[1]['avg_rating'],
        'num_books': best_decade[1]['num_books'],
        'total_reviews': best_decade[1]['total_reviews'],
        'all_decades': {decade: stats for decade, stats in decade_stats.items()}
    }
else:
    result = {'error': 'No decades with sufficient data'}

print('__RESULT__:')
print(json.dumps(result, indent=2))

